+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+
+codeunit 30370 "Shpfy Copy Document Handler"
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnAfterCopySalesHeaderDone', '', false, false)]
+    local procedure OnAfterCopySalesHeaderDone(
+        var ToSalesHeader: Record "Sales Header";
+        _OldSalesHeader: Record "Sales Header";
+        _FromSalesHeader: Record "Sales Header";
+        _FromSalesShipmentHeader: Record "Sales Shipment Header";
+        _FromSalesInvoiceHeader: Record "Sales Invoice Header";
+        _FromReturnReceiptHeader: Record "Return Receipt Header";
+        _FromSalesCrMemoHeader: Record "Sales Cr.Memo Header";
+        _FromSalesHeaderArchive: Record "Sales Header Archive";
+        FromDocType: Enum "Sales Document Type From")
+    begin
+        if ShouldClearShpfyFields(ToSalesHeader, FromDocType) then
+            ClearShpfyFields(ToSalesHeader);
+    end;
+
+    local procedure ShouldClearShpfyFields(var ToSalesHeader: Record "Sales Header"; FromDocType: Enum "Sales Document Type From"): Boolean
+    begin
+        exit(
+          (FromDocType = "Sales Document Type From"::Invoice or FromDocType = "Sales Document Type From"::"Posted Invoice") and
+          ToSalesHeader."Document Type" = ToSalesHeader."Document Type"::Invoice and
+          (ToSalesHeader."Shpfy Order Id" <> 0 or ToSalesHeader."Shpfy Order No." <> ''));
+    end;
+
+    local procedure ClearShpfyFields(var SalesHeader: Record "Sales Header")
+    begin
+        SalesHeader."Shpfy Order Id" := 0;
+        SalesHeader."Shpfy Order No." := '';
+        SalesHeader.Modify(true);
+    end;
+}

