+    local procedure NormalizeContractEntryFilter(var ContractEntryNoFilter: Text)
+    var
+        RemainingFilter: Text;
+        FilterSegment: Text;
+    begin
+        RemainingFilter := ContractEntryNoFilter;
+        if RemainingFilter = '' then
+            exit;
+
+        ContractEntryNoFilter := '';
+        while RemainingFilter <> '' do begin
+            if STRPOS(RemainingFilter, '|') > 0 then begin
+                FilterSegment := COPYSTR(RemainingFilter, 1, STRPOS(RemainingFilter, '|') - 1);
+                RemainingFilter := COPYSTR(RemainingFilter, STRPOS(RemainingFilter, '|') + 1);
+            end else begin
+                FilterSegment := RemainingFilter;
+                RemainingFilter := '';
+            end;
+
+            FilterSegment := NormalizeContractEntryRange(FilterSegment);
+            if FilterSegment = '' then
+                continue;
+
+            if ContractEntryNoFilter <> '' then
+                ContractEntryNoFilter += '|';
+            ContractEntryNoFilter += FilterSegment;
+        end;
+    end;
+
+    local procedure NormalizeContractEntryRange(FilterSegment: Text): Text
+    var
+        RangeDelimiter: Integer;
+        StartText: Text;
+        EndText: Text;
+        StartValue: Integer;
+        EndValue: Integer;
+    begin
+        RangeDelimiter := STRPOS(FilterSegment, '..');
+        if RangeDelimiter = 0 then
+            exit(FilterSegment);
+
+        StartText := COPYSTR(FilterSegment, 1, RangeDelimiter - 1);
+        EndText := COPYSTR(FilterSegment, RangeDelimiter + 2);
+        StartText := DelChr(StartText, '''');
+        EndText := DelChr(EndText, '''');
+        if not Evaluate(StartValue, StartText) or not Evaluate(EndValue, EndText) then
+            exit(FilterSegment);
+
+        if StartValue <= EndValue then
+            exit(Format(StartValue) + '..' + Format(EndValue));
+        exit(Format(EndValue) + '..' + Format(StartValue));
+    end;
+
