diff --git a/App/Layers/W1/BaseApp/Sales/Reminder/ReminderEntryDimSync.Codeunit.al b/App/Layers/W1/BaseApp/Sales/Reminder/ReminderEntryDimSync.Codeunit.al
new file mode 100644
index 00000000..16d3dee7
--- /dev/null
+++ b/App/Layers/W1/BaseApp/Sales/Reminder/ReminderEntryDimSync.Codeunit.al
@@ -0,0 +1,61 @@
+namespace Microsoft.Sales.Reminder;
+
+using Microsoft.Finance.GeneralLedger.Journal;
+using Microsoft.Finance.GeneralLedger.Ledger;
+using Microsoft.Foundation.AuditCodes;
+using Microsoft.Sales.Receivables;
+
+codeunit 50101 "Reminder Entry Dim Sync"
+{
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Gen. Jnl.-Post Line", 'OnAfterCustLedgEntryInsert', '', false, false)]
+    local procedure OnAfterCustLedgEntryInsertReminder(var CustLedgerEntry: Record "Cust. Ledger Entry"; GenJournalLine: Record "Gen. Journal Line"; var DtldLedgEntryInserted: Boolean; PreviewMode: Boolean)
+    var
+        SourceCodeSetup: Record "Source Code Setup";
+        GLEntry: Record "G/L Entry";
+        ReminderSourceCode: Code[10];
+        NewShortcutDim1: Code[20];
+        NewShortcutDim2: Code[20];
+        CustDimChanged: Boolean;
+    begin
+        if PreviewMode then
+            exit;
+
+        if not SourceCodeSetup.Get() then
+            exit;
+
+        ReminderSourceCode := SourceCodeSetup."Reminder";
+        if (ReminderSourceCode = '') or (GenJournalLine."Source Code" <> ReminderSourceCode) then
+            exit;
+
+        NewShortcutDim1 := GenJournalLine."Shortcut Dimension 1 Code";
+        NewShortcutDim2 := GenJournalLine."Shortcut Dimension 2 Code";
+
+        if CustLedgerEntry."Global Dimension 1 Code" <> NewShortcutDim1 then begin
+            CustLedgerEntry."Global Dimension 1 Code" := NewShortcutDim1;
+            CustDimChanged := true;
+        end;
+        if CustLedgerEntry."Global Dimension 2 Code" <> NewShortcutDim2 then begin
+            CustLedgerEntry."Global Dimension 2 Code" := NewShortcutDim2;
+            CustDimChanged := true;
+        end;
+        if CustDimChanged then
+            CustLedgerEntry.Modify();
+
+        GLEntry.SetRange("Document Type", GenJournalLine."Document Type");
+        GLEntry.SetRange("Document No.", GenJournalLine."Document No.");
+        GLEntry.SetRange("G/L Account No.", GenJournalLine."Account No.");
+        GLEntry.SetRange("Posting Date", GenJournalLine."Posting Date");
+        if GLEntry.FindSet(true, true) then
+            repeat
+                if (GLEntry."Global Dimension 1 Code" <> NewShortcutDim1) or
+                   (GLEntry."Global Dimension 2 Code" <> NewShortcutDim2) or
+                   (GLEntry."Dimension Set ID" <> GenJournalLine."Dimension Set ID")
+                then begin
+                    GLEntry."Global Dimension 1 Code" := NewShortcutDim1;
+                    GLEntry."Global Dimension 2 Code" := NewShortcutDim2;
+                    GLEntry."Dimension Set ID" := GenJournalLine."Dimension Set ID";
+                    GLEntry.Modify();
+                end;
+            until GLEntry.Next() = 0;
+    end;
+}

